def maximumPrimeDifference(nums):
    def is_prime(n):
        if n <= 1:
            return False
        if n <= 3:
            return True
        if n % 2 == 0 or n % 3 == 0:
            return False
        i = 5
        while i * i <= n:
            if n % i == 0 or n % (i + 2) == 0:
                return False
            i += 6
        return True
    min_idx = float('inf')
    max_idx = -float('inf')
    for i, num in enumerate(nums):
        if is_prime(num):
            if i < min_idx:
                min_idx = i
            if i > max_idx:
                max_idx = i
    return max_idx - min_idx
